diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..f10ae70c7f07 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3344,8 +3344,123 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         Neg->takeName(BO);
         return new ICmpInst(Pred, BOp0, Neg);
       }
+    } else {
+      // (zext i1 A) + (zext i1 B) == C --> ...
+      // (sext i1 A) + (sext i1 B) == C --> ...
+      // (zext i1 A) + (sext i1 B) == C --> ...
+      // The sum of two i1 extensions can only take a few values,
+      // depending on the extension kinds.
+      Value *A, *B;
+      bool AIsSExt = match(BOp0, m_SExt(m_Value(A)));
+      bool BIsSExt = match(BOp1, m_SExt(m_Value(B)));
+      if ((AIsSExt || match(BOp0, m_ZExt(m_Value(A)))) &&
+          (BIsSExt || match(BOp1, m_ZExt(m_Value(B)))) &&
+          A->getType()->isIntOrIntVectorTy(1) &&
+          B->getType()->isIntOrIntVectorTy(1)) {
+        // Determine the valid sum range and produce boolean expression.
+        // zext produces {0, 1}, sext produces {0, -1}.
+        // Possible sums:
+        //   zext+zext: 0, 1, 2      (false+false=0, one+one=2, xor=1)
+        //   sext+sext: 0, -1, -2    (false+false=0, one+one=-2, xor=-1)
+        //   sext+zext: -1, 0, 1     (true+false=-1, false+true=1, same=0)
+        //   zext+sext: -1, 0, 1     (same as above with operands swapped)
+        bool IsEQ = Pred == ICmpInst::ICMP_EQ;
+
+        Instruction *Result = nullptr;
+
+        if (!AIsSExt && !BIsSExt) {
+          // Both zext: possible sums are 0, 1, 2
+          if (C.isZero()) {
+            // sum == 0: both false -> !A && !B -> !(A || B)
+            if (IsEQ) {
+              Value *Or = Builder.CreateOr(A, B);
+              Result = BinaryOperator::CreateNot(Or);
+            } else
+              Result = BinaryOperator::CreateOr(A, B);
+          } else if (C.isOne()) {
+            // sum == 1: one true, one false -> A xor B
+            if (IsEQ)
+              Result = BinaryOperator::CreateXor(A, B);
+            else
+              Result = BinaryOperator::CreateNot(Builder.CreateXor(A, B));
+          } else if (C == 2) {
+            // sum == 2: both true -> A && B
+            if (IsEQ)
+              Result = BinaryOperator::CreateAnd(A, B);
+            else
+              Result = BinaryOperator::CreateOr(Builder.CreateNot(A),
+                                                Builder.CreateNot(B));
+          } else {
+            // Constant outside valid range; result is constant
+            Result = replaceInstUsesWith(
+                Cmp, ConstantInt::getBool(Cmp.getContext(), !IsEQ));
+          }
+        } else if (AIsSExt && BIsSExt) {
+          // Both sext: possible sums are 0, -1, -2
+          if (C.isZero()) {
+            // sum == 0: both false -> !(A || B)
+            if (IsEQ) {
+              Value *Or = Builder.CreateOr(A, B);
+              Result = BinaryOperator::CreateNot(Or);
+            } else
+              Result = BinaryOperator::CreateOr(A, B);
+          } else if (C.isAllOnes()) {
+            // sum == -1: one true, one false -> A xor B
+            if (IsEQ)
+              Result = BinaryOperator::CreateXor(A, B);
+            else
+              Result = BinaryOperator::CreateNot(Builder.CreateXor(A, B));
+          } else if (C == -2) {
+            // sum == -2: both true -> A && B
+            if (IsEQ)
+              Result = BinaryOperator::CreateAnd(A, B);
+            else
+              Result = BinaryOperator::CreateOr(Builder.CreateNot(A),
+                                                Builder.CreateNot(B));
+          } else {
+            // Constant outside valid range
+            Result = replaceInstUsesWith(
+                Cmp, ConstantInt::getBool(Cmp.getContext(), !IsEQ));
+          }
+        } else {
+          // Mixed sext and zext: possible sums are -1, 0, 1
+          // Normalize so that A is the sext operand, B is the zext operand
+          if (!AIsSExt) std::swap(A, B);
+          // sext A + zext B:
+          //   A=0,B=0 -> 0
+          //   A=0,B=1 -> 1
+          //   A=1,B=0 -> -1
+          //   A=1,B=1 -> 0
+          if (C.isZero()) {
+            // sum == 0: (A=0,B=0) or (A=1,B=1) -> !(A xor B)
+            Value *Xor = Builder.CreateXor(A, B);
+            Result = IsEQ ? BinaryOperator::CreateNot(Xor)
+                          : cast<Instruction>(Xor);
+          } else if (C.isOne()) {
+            // sum == 1: A=0,B=1 -> !A && B
+            if (IsEQ)
+              Result = BinaryOperator::CreateAnd(Builder.CreateNot(A), B);
+            else
+              // ne: !(!A && B) = A || !B
+              Result = BinaryOperator::CreateOr(A, Builder.CreateNot(B));
+          } else if (C.isAllOnes()) {
+            // sum == -1: A=1,B=0 -> A && !B
+            if (IsEQ)
+              Result = BinaryOperator::CreateAnd(A, Builder.CreateNot(B));
+            else
+              // ne: !(A && !B) = !A || B
+              Result = BinaryOperator::CreateOr(Builder.CreateNot(A), B);
+          } else {
+            // Constant outside valid range
+            Result = replaceInstUsesWith(
+                Cmp, ConstantInt::getBool(Cmp.getContext(), !IsEQ));
+          }
+        }
+
+        if (Result)
+          return Result;
+      }
     }
-    break;
   }
   case Instruction::Xor:
     if (BO->hasOneUse()) {

